CometChatUserEvents.ccUserBlocked = new rxjs.Subject();
CometChatUserEvents.ccUserUnblocked = new rxjs.Subject();

class ChatSdkEventInitializer {
    static attachListeners() {
        chatSdkJavascript.CometChat.addMessageListener(this.messageListenerId, this.getMessageListenerObject());
    }
    static detachListeners() {
        chatSdkJavascript.CometChat.removeMessageListener(this.messageListenerId);
    }
    static getMessageListenerObject() {
        return new chatSdkJavascript.CometChat.MessageListener({
            onTextMessageReceived: (textMessage) => {
                CometChatMessageEvents.onTextMessageReceived.next(textMessage);
            },
            onMediaMessageReceived: (mediaMessage) => {
                CometChatMessageEvents.onMediaMessageReceived.next(mediaMessage);
            },
            onCustomMessageReceived: (customMessage) => {
                CometChatMessageEvents.onCustomMessageReceived.next(customMessage);
            },
            onSchedulerMessageReceived: (message) => {
                CometChatMessageEvents.onSchedulerMessageReceived.next(message);
            },
            onTypingStarted: (typingIndicator) => {
                CometChatMessageEvents.onTypingStarted.next(typingIndicator);
            },
            onTypingEnded: (typingIndicator) => {
                CometChatMessageEvents.onTypingEnded.next(typingIndicator);
            },
            onMessagesDelivered: (messageReceipt) => {
                CometChatMessageEvents.onMessagesDelivered.next(messageReceipt);
            },
            onMessagesRead: (messageReceipt) => {
                CometChatMessageEvents.onMessagesRead.next(messageReceipt);
            },
            onMessagesDeliveredToAll: (messageReceipt) => {
                CometChatMessageEvents.onMessagesDeliveredToAll.next(messageReceipt);
            },
            onMessagesReadByAll: (messageReceipt) => {
                CometChatMessageEvents.onMessagesReadByAll.next(messageReceipt);
            },
            onMessageEdited: (message) => {
                message = classRectifier(message);
                CometChatMessageEvents.onMessageEdited.next(message);
            },
            onMessageDeleted: (message) => {
                message = classRectifier(message);
                CometChatMessageEvents.onMessageDeleted.next(message);
            },
            onTransientMessageReceived: (message) => {
                CometChatMessageEvents.onTransientMessageReceived.next(message);
            },
            onInteractionGoalCompleted: (receipt) => {
                CometChatMessageEvents.onInteractionGoalCompleted.next(receipt);
            },
            onInteractiveMessageReceived: (message) => {
                switch (message.getType()) {
                    case CometChatUIKitConstants.MessageTypes.form:
                        const formMessage = FormMessage.fromJSON(message);
                        CometChatMessageEvents.onFormMessageReceived.next(formMessage);
                        break;
                    case CometChatUIKitConstants.MessageTypes.card:
                        const cardMessage = CardMessage.fromJSON(message);
                        CometChatMessageEvents.onCardMessageReceived.next(cardMessage);
                        break;
                    default:
                        const customInteractiveMessage = CustomInteractiveMessage.fromJSON(message);
                        CometChatMessageEvents.onCustomInteractiveMessageReceived.next(customInteractiveMessage);
                        break;
                }
            },
            onMessageReactionAdded: (reaction) => {
                CometChatMessageEvents.onMessageReactionAdded.next(reaction);
            },
            onMessageReactionRemoved: (reaction) => {
                CometChatMessageEvents.onMessageReactionRemoved.next(reaction);
            }
        });
    }
}
ChatSdkEventInitializer.messageListenerId = `message_listener_${new Date().getTime()}`;
function classRectifier(message) {
    if (message.getCategory() === CometChatUIKitConstants.MessageCategory.interactive) {
        switch (message.getType()) {
            case CometChatUIKitConstants.MessageTypes.form:
                return FormMessage.fromJSON(message);
            case CometChatUIKitConstants.MessageTypes.card:
                return CardMessage.fromJSON(message);
            case CometChatUIKitConstants.MessageTypes.scheduler:
                return SchedulerMessage.fromJSON(message);
            default:
                return CustomInteractiveMessage.fromJSON(message);
        }
    }
    else {
        return message;
    }
}

